# @cctt_verify {"v":2,"sym":"sympy.physics.qho_1d.E_n","kind":"function","src_hash":"630612dfeb3f619e","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"E_n(n, )","rhs":"returns the energy of the one-dimensional harmonic oscillator","over":{"base":"Any"},"name":"E_n_correct"},"guarantee":"returns the energy of the one-dimensional harmonic oscillator","fibers":[],"h1":0,"paths":[],"strategy":"refl","details":{},"assumes":[],"trust":["lean.C4.Reduction.ReducesStar.refl"],"compiled":true,"vhash":"f05d1c650c1352ef"}
def E_n(n, omega):
    """
    Returns the Energy of the One-dimensional harmonic oscillator.

    Parameters
    ==========

    n :
        The "nodal" quantum number.
    omega :
        The harmonic oscillator angular frequency.

    Notes
    =====

    The unit of the returned value matches the unit of hw, since the energy is
    calculated as:

        E_n = hbar * omega*(n + 1/2)

    Examples
    ========

    >>> from sympy.physics.qho_1d import E_n
    >>> from sympy.abc import x, omega
    >>> E_n(x, omega)
    hbar*omega*(x + 1/2)
    """

    return hbar * omega * (n + S.Half)


